import { SSECommand } from "../shared/type";

const content = document.getElementById("content") as HTMLDivElement;
const screen = (window as any).__screen || "----";

const appName = "team-name-" + screen;

// Add background image
content.style.backgroundImage = "url('/img/name.png')";
content.style.backgroundSize = "cover";
content.style.backgroundPosition = "center";
content.style.backgroundRepeat = "no-repeat";
content.style.position = "relative";

// Add centered text field
const textInfo = document.createElement("div");
textInfo.id = "scoreText";
textInfo.style.position = "absolute";
textInfo.style.top = "50%";
textInfo.style.left = "50%";
textInfo.style.transform = "translate(-50%, -50%)";
textInfo.style.color = "white";
textInfo.style.textAlign = "center";
textInfo.style.whiteSpace = "nowrap";

content.appendChild(textInfo);

// Reference text for scaling: "FooBar FooBar" should be 80% of viewport width
const REFERENCE_TEXT = "FooBar FooBar";
const TARGET_WIDTH_RATIO = 0.8;

/**
 * Calculates and applies font size so the reference text takes 80% of viewport width
 */
const scaleFontSize = (): void => {
    const viewportWidth = window.innerWidth;
    const targetWidth = viewportWidth * TARGET_WIDTH_RATIO;

    // Create a hidden measurement element
    const measurer = document.createElement("span");
    measurer.style.position = "absolute";
    measurer.style.visibility = "hidden";
    measurer.style.whiteSpace = "nowrap";
    measurer.style.font = window.getComputedStyle(textInfo).font || "inherit";
    measurer.style.fontSize = "100px"; // Base size for measurement
    measurer.textContent = REFERENCE_TEXT;
    document.body.appendChild(measurer);

    const measuredWidth = measurer.offsetWidth;
    document.body.removeChild(measurer);

    // Calculate the font size needed for target width
    const scaledFontSize = (targetWidth / measuredWidth) * 100;
    textInfo.style.fontSize = `${scaledFontSize}px`;
    console.log(`[${appName}] scaling font size ${scaledFontSize}px for target width ${targetWidth}px`);
};

// Initial text and scaling
textInfo.textContent = screen;
scaleFontSize();

// Rescale on window resize
window.addEventListener("resize", scaleFontSize);

console.log(`[${screen}] initialized`);

/**
 * Handles incoming SSE commands
 * @param command - The SSE command to process
 */
const handleSSECommand = (command: SSECommand): void => {
    switch (command.type) {
        case 'name':
            if (command.screen && command.screen === screen) {
                if (command.value) {
                    textInfo.textContent = command.value;
                } else {
                    textInfo.textContent = '';
                }
            }
            break;
        default:
            console.log(`[${appName}] SSE unhandled command: ` + JSON.stringify(command));
    }
};

/**
 * Initializes SSE connection to listen for mesh commands
 * @param sseUrl - The URL of the SSE endpoint (default: '/api/sse')
 */
const initSSE = (sseUrl: string = '/api/sse'): void => {
    const eventSource = new EventSource(sseUrl);

    eventSource.onopen = () => {
        console.log(`[${appName}] SSE connection established`);
    };

    eventSource.onmessage = (event: MessageEvent) => {
        try {
            const command: SSECommand = JSON.parse(event.data);
            handleSSECommand(command);
        } catch (error) {
            console.error(`[${appName}] SSE failed to parse command:`, error);
        }
    };

    eventSource.onerror = (error) => {
        console.error(`[${appName}] SSE connection error:`, error);
        // EventSource will automatically attempt to reconnect
    };

    // Store reference for potential cleanup
    (window as Window & { __sseEventSource?: EventSource }).__sseEventSource = eventSource;
};

initSSE();

